#!/usr/bin/env python3
"""
Simple test to understand the current color behavior.
"""

import click

def test_click_color_behavior():
    """Test how click handles color parameter."""

    print("=== Testing Click Color Behavior ===")

    # Test 1: color=None (autodetection)
    print("\n1. click.echo with color=None:")
    try:
        # This should autodetect - no colors when piped
        click.echo("This is a test message", color=None)
    except Exception as e:
        print(f"Error: {e}")

    # Test 2: color=True (force colors)  
    print("\n2. click.echo with color=True:")
    try:
        click.echo("This is a test message", color=True)
    except Exception as e:
        print(f"Error: {e}")

    # Test 3: color=False (no colors)
    print("\n3. click.echo with color=False:")
    try:
        click.echo("This is a test message", color=False)
    except Exception as e:
        print(f"Error: {e}")

if __name__ == '__main__':
    test_click_color_behavior()

